public class StringUtils {
    static String padLeft(String s, int width, char c) {
        StringBuilder sb = new StringBuilder();
        for (int i = s.length(); i < width; i++) sb.append(c);
        sb.append(s);
        return sb.toString();
    }
    public static void main(String[] args) {
        System.out.println(padLeft("hi", 5, '-'));
        System.out.println(padLeft("hello", 3, '*'));
        System.out.println(padLeft("", 3, 'X'));
    }
}
